6 #ifndef MODEL_PREFABS_H
7 #define MODEL_PREFABS_H
8 
9 #include <memory>
10 
11 #include "Rendering/Materials/MaterialDefaults.h"
12 #include "Rendering/Geometry/ModelPartPrefabs.h"
13 #include "Rendering/Geometry/Model.h"
14 
16 struct ModelPrefabs{
18     struct CubeMaterialDefinition{
19         PMaterial matTop = MaterialDefaults::ColorMaterial::Create(Color::MAGENTA);
20         PMaterial matBottom = MaterialDefaults::ColorMaterial::Create(Color::MAGENTA);
21         PMaterial matLeft = MaterialDefaults::ColorMaterial::Create(Color::MAGENTA);
22         PMaterial matRight = MaterialDefaults::ColorMaterial::Create(Color::MAGENTA);
23         PMaterial matFront = MaterialDefaults::ColorMaterial::Create(Color::MAGENTA);
24         PMaterial matBack = MaterialDefaults::ColorMaterial::Create(Color::MAGENTA);
25 
26 
31         static std::shared_ptr<CubeMaterialDefinition> Create() {return std::make_shared<CubeMaterialDefinition>();};
32         static std::shared_ptr<CubeMaterialDefinition> CreateSame(PMaterial mat) {
33             auto def = std::make_shared<CubeMaterialDefinition>();
34             def->matFront = mat;
35             def->matBack = mat;
36             def->matLeft = mat;
37             def->matRight = mat;
38             def->matTop = mat;
39             def->matBottom = mat;
40             return def;
41         };
42     };
43 
50     static std::shared_ptr<Model> MakeCube(float scale = 1.0f, std::shared_ptr<CubeMaterialDefinition> matDef = CubeMaterialDefinition::Create()){
51 
52         auto model = Model::Create();
53 
54         std::shared_ptr<ModelPart> cubeTop = ModelPartPrefabs::MakePlane(scale, scale, matDef->matTop);
55         cubeTop->localTransform.setPosition(Math3D::Vec3(0.0f,1.0f,0.0f));
56         cubeTop->localTransform.setRotation(0.0f,0.0f,0.0f);
57 
58         std::shared_ptr<ModelPart> cubeBottom = ModelPartPrefabs::MakePlane(scale, scale, matDef->matBottom);
59         cubeBottom->localTransform.setPosition(Math3D::Vec3(0.0f,-1.0f,0.0f));
60         cubeBottom->localTransform.setRotation(180.0f,0.0f,0.0f);
61 
62         std::shared_ptr<ModelPart> cubeLeft = ModelPartPrefabs::MakePlane(scale, scale, matDef->matLeft);
63         cubeLeft->localTransform.setPosition(Math3D::Vec3(-1.0f,0.0f,0.0f));
64         cubeLeft->localTransform.setRotation(0.0f,-90.0f,90.0f);
65 
66         std::shared_ptr<ModelPart> cubeRight = ModelPartPrefabs::MakePlane(scale, scale, matDef->matRight);
67         cubeRight->localTransform.setPosition(Math3D::Vec3(1.0f,0.0f,0.0f));
68         cubeRight->localTransform.setRotation(0.0f,90.0f,-90.0f);
69 
70         std::shared_ptr<ModelPart> cubeFront = ModelPartPrefabs::MakePlane(scale, scale, matDef->matFront);
71         cubeFront->localTransform.setPosition(Math3D::Vec3(0.0f,0.0f,1.0f));
72         cubeFront->localTransform.setRotation(-90.0f,180.0f,180.0f);
73 
74         std::shared_ptr<ModelPart> cubeBack = ModelPartPrefabs::MakePlane(scale, scale, matDef->matBack);
75         cubeBack->localTransform.setPosition(Math3D::Vec3(0.0f,0.0f,-1.0f));
76         cubeBack->localTransform.setRotation(90.0f,180.0f,0.0f);
77 
78         model->addPart(cubeTop).addPart(cubeBottom).addPart(cubeLeft).addPart(cubeRight).addPart(cubeFront).addPart(cubeBack);
79 
80         return model;
81     }
82 };
83 
84 #endif // MODEL_PREFABS_H
